import React from "react";
import { useParams } from "react-router-dom";
import DnDForm from "../Character/Forms/DnDForm";
import PathFinderForm from "../Character/Forms/PathFinderForm";
import CallOfCthulhuForm from "../Character/Forms/CallOfCthulhuForm";
import VaesenForm from "../Character/Forms/VaesenForm";
import CustomForm from "../Character/Forms/CustomForm";

const CreateCharacterPage = () => {
  const { system } = useParams();

  const renderForm = () => {
    switch (system) {
      case "dnd":
        return <DnDForm />;
      case "pathfinder":
        return <PathFinderForm />;
      case "call-of-cthulhu":
        return <CallOfCthulhuForm />;
      case "vaesen":
        return <VaesenForm />;
      case "custom":
        return <CustomForm />;
      default:
        return <p>Невідома система</p>;
    }
  };

  return <div className="create-character-page">{renderForm()}</div>;
};

export default CreateCharacterPage;
